import { NextResponse } from 'next/server';

export async function POST(request) {
  try {
    const { number } = await request.json();

    if (!number) {
      return NextResponse.json(
        { error: 'NIN number is required' },
        { status: 400 }
      );
    }

    const appId = process.env.PREMBLY_APP_ID;
    const apiKey = process.env.PREMBLY_API_KEY;

    if (!appId || !apiKey) {
      return NextResponse.json(
        { error: 'Prembly configuration is missing' },
        { status: 500 }
      );
    }

    const response = await fetch('https://api.prembly.com/api/v1/verification/nin', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'app-id': appId,
        'x-api-key': apiKey,
      },
      body: JSON.stringify({ number }),
    });

    const data = await response.json();

    return NextResponse.json(data, { status: response.status });
  } catch (error) {
    console.error('Error verifying NIN:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

